#include <algorithm>
#include <cmath>
#include <initializer_list>
#include <iostream>
#include <sstream>
#include <string>
#include <vector>

class Polynomial {
public:
    Polynomial() = default;
    Polynomial(std::initializer_list<double> coeffs) : c_(coeffs) { trim(); }
    explicit Polynomial(const std::vector<double>& coeffs) : c_(coeffs) { trim(); }

    int degree() const { return c_.empty() ? 0 : static_cast<int>(c_.size()) - 1; }

    double operator()(double x) const {
        double result = 0.0;
        for (auto it = c_.rbegin(); it != c_.rend(); ++it) result = result * x + *it;
        return result;
    }

    Polynomial operator+(const Polynomial& other) const {
        std::vector<double> out(std::max(c_.size(), other.c_.size()), 0.0);
        for (std::size_t i = 0; i < c_.size(); ++i) out[i] += c_[i];
        for (std::size_t i = 0; i < other.c_.size(); ++i) out[i] += other.c_[i];
        return Polynomial(out);
    }

    Polynomial operator*(const Polynomial& other) const {
        if (c_.empty() || other.c_.empty()) return Polynomial{};
        std::vector<double> out(c_.size() + other.c_.size() - 1, 0.0);
        for (std::size_t i = 0; i < c_.size(); ++i)
            for (std::size_t j = 0; j < other.c_.size(); ++j)
                out[i + j] += c_[i] * other.c_[j];
        return Polynomial(out);
    }

    Polynomial derivative() const {
        if (c_.size() <= 1) return Polynomial{0.0};
        std::vector<double> out(c_.size() - 1);
        for (std::size_t i = 1; i < c_.size(); ++i) out[i - 1] = c_[i] * static_cast<double>(i);
        return Polynomial(out);
    }

    friend std::ostream& operator<<(std::ostream& os, const Polynomial& p) {
        if (p.c_.empty()) return os << "0";
        bool first = true;
        for (int i = static_cast<int>(p.c_.size()) - 1; i >= 0; --i) {
            double v = p.c_[i];
            if (v == 0.0) continue;
            double a = v < 0 ? -v : v;
            if (first) { if (v < 0) os << "-"; }
            else os << (v < 0 ? " - " : " + ");
            if (!(a == 1.0 && i != 0)) os << fmt(a);
            if (i >= 1) os << "x";
            if (i >= 2) os << "^" << i;
            first = false;
        }
        if (first) os << "0";
        return os;
    }

private:
    static std::string fmt(double v) {
        std::ostringstream os;
        if (v == static_cast<long long>(v)) os << static_cast<long long>(v);
        else os << v;
        return os.str();
    }
    void trim() { while (c_.size() > 1 && c_.back() == 0.0) c_.pop_back(); }
    std::vector<double> c_;
};

static std::string fmt_num(double v) {
    std::ostringstream os;
    double r = std::round(v * 1000.0) / 1000.0;
    if (r == 0.0) r = 0.0;
    if (r == static_cast<long long>(r)) os << static_cast<long long>(r);
    else os << r;
    return os.str();
}

int main() {
    std::vector<Polynomial> store;
    std::string line;
    while (std::getline(std::cin, line)) {
        if (line.empty()) continue;
        std::istringstream iss(line);
        std::string cmd;
        iss >> cmd;
        if (cmd == "POLY") {
            int n; iss >> n;
            std::vector<double> coeffs(n + 1);
            for (int i = 0; i <= n; ++i) iss >> coeffs[i];
            store.push_back(Polynomial(coeffs));
            std::cout << "#" << store.size() - 1 << ": " << store.back() << "\n";
        } else if (cmd == "EVAL") {
            std::size_t id; double x; iss >> id >> x;
            std::cout << fmt_num(store[id](x)) << "\n";
        } else if (cmd == "ADD" || cmd == "MUL") {
            std::size_t a, b; iss >> a >> b;
            store.push_back(cmd == "ADD" ? store[a] + store[b] : store[a] * store[b]);
            std::cout << "#" << store.size() - 1 << ": " << store.back() << "\n";
        } else if (cmd == "DERIV") {
            std::size_t a; iss >> a;
            store.push_back(store[a].derivative());
            std::cout << "#" << store.size() - 1 << ": " << store.back() << "\n";
        } else if (cmd == "LIST") {
            std::vector<std::size_t> idx(store.size());
            for (std::size_t i = 0; i < idx.size(); ++i) idx[i] = i;
            std::sort(idx.begin(), idx.end(), [&](std::size_t a, std::size_t b) {
                if (store[a].degree() != store[b].degree()) return store[a].degree() < store[b].degree();
                return a < b;
            });
            int nonconst = static_cast<int>(std::count_if(store.begin(), store.end(),
                [](const Polynomial& p) { return p.degree() > 0; }));
            std::cout << "count=" << store.size() << " nonconst=" << nonconst << "\n";
            std::for_each(idx.begin(), idx.end(), [&](std::size_t i) {
                std::cout << "#" << i << " [deg " << store[i].degree() << "]: " << store[i] << "\n";
            });
        } else if (cmd == "TABLE") {
            std::size_t id; double x0, x1, step; iss >> id >> x0 >> x1 >> step;
            int n = static_cast<int>(std::round((x1 - x0) / step)) + 1;
            if (n < 1) n = 1;
            double* xs = new double[n];
            double* ys = new double[n];
            for (int i = 0; i < n; ++i) { xs[i] = x0 + step * i; ys[i] = store[id](xs[i]); }
            for (int i = 0; i < n; ++i) std::cout << fmt_num(xs[i]) << " -> " << fmt_num(ys[i]) << "\n";
            delete[] xs;
            delete[] ys;
        }
    }
    return 0;
}
